"use client"

import { SyncTerminalUI } from "./sync-terminal-ui"
import {
  useSyncTerminal,
  type SyncEvent,
  type SyncStatus,
} from "./use-sync-terminal"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { SyncTerminalUI, type SyncTerminalUIProps } from "./sync-terminal-ui"
export {
  useSyncTerminal,
  type UseSyncTerminalOptions,
  type UseSyncTerminalReturn,
  type SyncEvent,
  type SyncEventLevel,
  type SyncStatus,
} from "./use-sync-terminal"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Props for the composed SyncTerminal block */
export interface SyncTerminalProps {
  /** Events to display in the terminal */
  events: SyncEvent[]
  /** Optional sync status shown in the header */
  status?: SyncStatus
  /** Maximum number of events to retain in the buffer (default: 200) */
  maxEvents?: number
  /** Header title (default: "Sync Log") */
  title?: string
  /** Show timestamps in each line (default: true) */
  showTimestamps?: boolean
  /** Show source labels in each line (default: true) */
  showSource?: boolean
  /** Whether to auto-scroll to the latest event (default: true) */
  autoScroll?: boolean
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * Monospace event log for blockchain sync activity with colour-coded severity
 * levels. Composes the `useSyncTerminal` hook with the `SyncTerminalUI`
 * presentation component.
 *
 * Accepts an array of events from the outside and manages the internal buffer
 * (capped at `maxEvents`) and auto-scroll behaviour automatically.
 *
 * @example
 * ```tsx
 * import { SyncTerminal } from "@/components/blocks/sync-terminal"
 *
 * function Dashboard() {
 *   const [events, setEvents] = useState<SyncEvent[]>([])
 *
 *   return (
 *     <SyncTerminal
 *       events={events}
 *       status={{ blockHeight: 850123, connected: true }}
 *       maxEvents={500}
 *     />
 *   )
 * }
 * ```
 */
export function SyncTerminal({
  events,
  status,
  maxEvents = 200,
  title = "Sync Log",
  showTimestamps = true,
  showSource = true,
  autoScroll = true,
  className,
}: SyncTerminalProps) {
  const { events: buffered, bottomRef } = useSyncTerminal({
    events,
    maxEvents,
    autoScroll,
  })

  return (
    <SyncTerminalUI
      events={buffered}
      status={status}
      title={title}
      showTimestamps={showTimestamps}
      showSource={showSource}
      bottomRef={bottomRef}
      className={className}
    />
  )
}

"use client"

import { useRef, useEffect, useCallback } from "react"
import { cn } from "@/lib/utils"
import type { SyncEvent, SyncEventLevel, SyncStatus } from "./use-sync-terminal"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface SyncTerminalUIProps {
  /** Events to display in the terminal */
  events: SyncEvent[]
  /** Optional sync status shown in the header */
  status?: SyncStatus
  /** Header title (default: "Sync Log") */
  title?: string
  /** Show timestamps in each line (default: true) */
  showTimestamps?: boolean
  /** Show source labels in each line (default: true) */
  showSource?: boolean
  /** Ref to attach to the scroll sentinel at the bottom */
  bottomRef?: React.RefObject<HTMLDivElement | null>
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const LEVEL_COLORS: Record<SyncEventLevel, string> = {
  log: "text-zinc-400",
  warn: "text-amber-400",
  error: "text-rose-400",
  success: "text-emerald-400",
}

/** Format a unix-ms timestamp into HH:MM:SS.mmm */
function formatTimestamp(ts: number): string {
  const d = new Date(ts)
  const h = String(d.getHours()).padStart(2, "0")
  const m = String(d.getMinutes()).padStart(2, "0")
  const s = String(d.getSeconds()).padStart(2, "0")
  const ms = String(d.getMilliseconds()).padStart(3, "0")
  return `${h}:${m}:${s}.${ms}`
}

// ---------------------------------------------------------------------------
// UI
// ---------------------------------------------------------------------------

/**
 * Terminal-style event log display with colour-coded severity levels.
 *
 * Uses a dark background (bg-zinc-950) and monospace font regardless of theme
 * since this intentionally emulates a terminal console.
 *
 * @example
 * ```tsx
 * <SyncTerminalUI
 *   events={events}
 *   status={{ blockHeight: 850123, connected: true }}
 * />
 * ```
 */
export function SyncTerminalUI({
  events,
  status,
  title = "Sync Log",
  showTimestamps = true,
  showSource = true,
  bottomRef,
  className,
}: SyncTerminalUIProps) {
  const scrollContainerRef = useRef<HTMLDivElement | null>(null)

  // Auto-scroll when events change if we have a bottomRef
  useEffect(() => {
    if (bottomRef?.current) {
      bottomRef.current.scrollIntoView({ behavior: "smooth" })
    }
  }, [events.length, bottomRef])

  const renderStatusDot = useCallback(() => {
    if (!status) return null

    return (
      <div className="flex items-center gap-2 text-xs">
        <span
          className={cn(
            "inline-block size-2 rounded-full",
            status.connected ? "bg-emerald-400" : "bg-zinc-600"
          )}
          aria-label={status.connected ? "Connected" : "Disconnected"}
        />
        {status.connected && (
          <span className="text-zinc-500">
            #{status.blockHeight.toLocaleString()}
          </span>
        )}
      </div>
    )
  }, [status])

  return (
    <div
      className={cn(
        "flex flex-col overflow-hidden rounded-lg border border-zinc-800 bg-zinc-950 font-mono text-xs",
        className
      )}
    >
      {/* Header */}
      <div className="flex items-center justify-between border-b border-zinc-800 px-3 py-2">
        <span className="font-semibold text-zinc-300">{title}</span>
        {renderStatusDot()}
      </div>

      {/* Log area */}
      <div
        ref={scrollContainerRef}
        className="flex-1 overflow-y-auto p-3"
        style={{ maxHeight: 400 }}
        role="log"
        aria-live="polite"
        aria-label={title}
      >
        {events.length === 0 ? (
          <p className="text-zinc-600">No events yet.</p>
        ) : (
          <div className="flex flex-col gap-0.5">
            {events.map((event, i) => (
              <div
                key={`${event.timestamp}-${i}`}
                className="flex gap-2 leading-5"
              >
                {showTimestamps && (
                  <span className="shrink-0 text-zinc-600">
                    {formatTimestamp(event.timestamp)}
                  </span>
                )}
                {showSource && (
                  <span className="shrink-0 text-zinc-500">
                    [{event.source}]
                  </span>
                )}
                <span className={LEVEL_COLORS[event.level]}>
                  {event.message}
                </span>
              </div>
            ))}
            {/* Scroll sentinel */}
            <div ref={bottomRef} />
          </div>
        )}
      </div>
    </div>
  )
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Severity level for a sync event */
export type SyncEventLevel = "log" | "warn" | "error" | "success"

/** A single event entry in the sync terminal */
export interface SyncEvent {
  /** Unix timestamp in milliseconds */
  timestamp: number
  /** Origin of the event (e.g. "sync", "wallet", "http") */
  source: string
  /** Severity level */
  level: SyncEventLevel
  /** Human-readable message */
  message: string
}

/** Current sync status indicator */
export interface SyncStatus {
  /** Latest block height */
  blockHeight: number
  /** Whether the node/service is connected */
  connected: boolean
}

/** Options for the useSyncTerminal hook */
export interface UseSyncTerminalOptions {
  /** Initial events to populate the terminal with */
  events?: SyncEvent[]
  /** Maximum number of events to retain in the buffer (default: 200) */
  maxEvents?: number
  /** Whether to auto-scroll to the latest event (default: true) */
  autoScroll?: boolean
}

/** Return value of the useSyncTerminal hook */
export interface UseSyncTerminalReturn {
  /** Current buffered events (sliced to maxEvents) */
  events: SyncEvent[]
  /** Ref to attach to the scroll-bottom sentinel element */
  bottomRef: React.RefObject<HTMLDivElement | null>
  /** Append a single event to the buffer */
  push: (event: SyncEvent) => void
  /** Append multiple events to the buffer */
  pushMany: (events: SyncEvent[]) => void
  /** Clear all events */
  clear: () => void
  /** Whether auto-scroll is currently active */
  isAutoScroll: boolean
  /** Toggle auto-scroll on or off */
  setAutoScroll: (value: boolean) => void
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Manages the event buffer and auto-scroll behaviour for a sync terminal.
 *
 * Events are kept in a fixed-size ring buffer (default 200). When new events
 * are pushed and `autoScroll` is enabled, the hook scrolls the sentinel ref
 * into view after each render.
 *
 * @example
 * ```ts
 * const { events, bottomRef, push, clear } = useSyncTerminal({
 *   maxEvents: 500,
 * })
 *
 * push({ timestamp: Date.now(), source: "sync", level: "log", message: "Block 850001" })
 * ```
 */
export function useSyncTerminal(
  options: UseSyncTerminalOptions = {}
): UseSyncTerminalReturn {
  const {
    events: initialEvents,
    maxEvents = 200,
    autoScroll: initialAutoScroll = true,
  } = options

  const [buffer, setBuffer] = useState<SyncEvent[]>(
    () => initialEvents?.slice(-maxEvents) ?? []
  )
  const [isAutoScroll, setAutoScroll] = useState(initialAutoScroll)
  const bottomRef = useRef<HTMLDivElement | null>(null)

  // Scroll to bottom when buffer changes and auto-scroll is on
  useEffect(() => {
    if (isAutoScroll && bottomRef.current) {
      bottomRef.current.scrollIntoView({ behavior: "smooth" })
    }
  }, [buffer, isAutoScroll])

  // Sync external events prop into buffer when it changes
  const externalKey = useMemo(
    () => (initialEvents ? initialEvents.length : -1),
    [initialEvents]
  )

  useEffect(() => {
    if (initialEvents) {
      setBuffer(initialEvents.slice(-maxEvents))
    }
  }, [externalKey, maxEvents])

  const push = useCallback(
    (event: SyncEvent) => {
      setBuffer((prev) => {
        const next = [...prev, event]
        return next.length > maxEvents ? next.slice(-maxEvents) : next
      })
    },
    [maxEvents]
  )

  const pushMany = useCallback(
    (events: SyncEvent[]) => {
      setBuffer((prev) => {
        const next = [...prev, ...events]
        return next.length > maxEvents ? next.slice(-maxEvents) : next
      })
    },
    [maxEvents]
  )

  const clear = useCallback(() => {
    setBuffer([])
  }, [])

  return {
    events: buffer,
    bottomRef,
    push,
    pushMany,
    clear,
    isAutoScroll,
    setAutoScroll,
  }
}
